var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"얼마 뒤","JPN":"しばらくして","ENG":"A few days later","TWN":"不久後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 가변 심도 좌표\\n<color=#ff3636>필하모닉 홀</color>","JPN":"裏世界可変深度座標\\n<color=#ff3636>フィルハーモニーホール</color>","ENG":"Counterside Variable Depth Coordinates\\n<color=#ff3636>Philharmonic Hall</color>","TWN":"異界可變深度座標\\n<color=#ff3636>管弦樂廳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"야크샤 전대 및 연합 전대.\\n강습 작전 수행 중.\\n작전명 <color=#ffd34c>커튼콜</color>","JPN":"ヤクシャー戦隊および連合戦隊。\\n強襲作戦遂行中。\\n作戦名<color=#ffd34c>カーテンコール</color>","ENG":"The Yaksha Division and the Coalition Divisions.\\nConducting an Assault Operation.\\nOperation Name <color=#ffd34c>Curtain Call</color>","TWN":"夜叉戰隊與聯合戰隊。\\n強襲作戰執行中。\\n作戰代號：<color=#ffd34c>謝幕</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카! 함 내 기갑병력의 화력 투사를 최대로! 강하 포인트를 확보한다!","JPN":"モネカ！　艦内機甲兵力の火力を最大限まで上げて！　強化ポイントを確保する！","ENG":"Moneka! Maximize the firepower projection of all the armored units! Secure the drop point!","TWN":"莫奈卡！最大化艦艇裝甲部隊的火力投射！確保著陸點！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"지원을 약속한 다른 전대는 얼마나 도착했지?","JPN":"支援を約束した他戦隊は？","ENG":"How many divisions that were supposed to provide support have arrived?","TWN":"承諾支援的其他戰隊來了多少？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"현재 야크샤, 아르콘 전대가 가변 심도 다이브에 성공하였습니다!","JPN":"現在、ヤクシャー、アルコン戦隊が可変深度ダイブに成功しました！","ENG":"Currently, Yaksha and Arkon Division have successfully dived into the variable depths!","TWN":"目前，夜叉和阿勒坤戰隊已成功躍入可變深度！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L14_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이어서 다음 좌표가 갱신되면, 지원 병력을 보낸 카멜롯과 카르데나스 외 2개 전대가…….","JPN":"次の座標更新後、支援兵力を送ったキャメロットとカルデナスの他2戦隊が……","ENG":"When the next coordinates are updated, Camelot, Cardenas, and two other divisions who sent support troops will...","TWN":"再下一個座標更新時，派出援軍的卡梅羅和卡特納斯，以及另外兩個戰隊…… 。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"어라……? 병기개발국에서도 지원을 보내왔습니다……!","JPN":"え……？　兵器開発局からも支援が届きました……！","ENG":"Huh...? The Weapon Development Bureau also sent support...!","TWN":"嗯……？兵器開發局也派遣了支援……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"<color=#ffd34c>다 쓸어 버리는 불사신 괴물</color>……? 이게 뭐죠……?","JPN":"<color=#ffd34c>万物をなぎ払う不死身の怪物</color>……？　これは何でしょう……？","ENG":"<color=#ffd34c>Immortal monster of total destruction</color>...? What is this...?","TWN":"<color=#ffd34c>橫掃一切的不死怪物</color>……？那是什麼……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 쥐스틴이 개발국장에게 부탁한 모양이네.","JPN":"ふふ、ジュスティーヌが開発局長に頼んでくれたみたいね。","ENG":"Fu fuu. I assume Justine asked the chief of development a favor.","TWN":"呵呵，看來是潔絲婷向開發局求助了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하여간 쪼그매도 믿음직스럽다니까~","JPN":"小さいのに本当、頼もしい子なんだから。","ENG":"I always knew I could count on that little one.","TWN":"那個小鬼還是值得信賴的～"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"작전 구역의 전 연합 전대원!","JPN":"作戦区域の全連合戦隊員の皆さん！","ENG":"All coalition members in the operation zone!","TWN":"作戰區域的全體聯合戰隊員！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 작전에서 선두를 맡게 된 제4수색전대 야크샤의 주디 스위프트입니다.","JPN":"今回の作戦で先頭に立つことになった第4捜索戦隊ヤクシャーのジュディ・スウィフトです。","ENG":"I am Judy Swift of the 4th Recon Division Yaksha, who will be taking the lead on this operation.","TWN":"我是第4偵察戰隊夜叉的茱蒂·斯威福特，將負責此次的作戰。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"브리핑에서 말씀드렸다시피, 이번 강습작전은 속전속결이 가장 중요합니다.","JPN":"ブリーフィングでもお伝えした通り、今回の強襲作戦では速戦即決が成功の要になります。","ENG":"As I said in the briefing, the most important aspect of this entire assault operation is speed.","TWN":"正如我在簡報中所說，本次強襲作戰最重要的是速戰速決。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다른 전대가 현실에 부상중인 마에스트로의 발을 묶고 있는 사이…….","JPN":"他の戦隊が現実に浮上しているマエストロの足を引き留めている間……","ENG":"While the other divisions are slowing down Maestra who will be emerging in the Normalside...","TWN":"當其他戰隊在現世中阻攔躍出的指揮家時……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"저희는 이곳 필하모닉 홀을 공략. 엘리시움의 시설과 최고 단원들을 전부 격파합니다.","JPN":"私たちはここフィルハーモニーホールを攻略。エリシウムの施設および首席奏者全員を撃破します。","ENG":"we will attack Philharmonic Hall, and all of Elysium's facilities and Elite Members.","TWN":"我們的目標是攻佔這裡的管弦樂廳。破壞樂團的所有設施，剿滅她們的樂手。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 후, 악단을 잃어 전력이 약화된 마에스트로까지 공략을 시도합니다.","JPN":"その後、楽団を失い戦力が弱化したマエストロの攻略に力を集結します。","ENG":"Afterward, we will attempt a strike on Maestra, who will be weakened after losing her Orchestra.","TWN":"之後，再嘗試殲滅失去了樂團，實力被削弱的指揮家。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"부디, 이 작전으로 가증스러운 오케스트라 연주에 막을 내릴 수 있기를 기도하며.","JPN":"どうかこの作戦で、あの忌々しいオーケストラの幕を下ろすことができるように。","ENG":"I pray that with this operation being successful, we can finally put an end to the abominable orchestra performance.","TWN":"請祈禱，本次作戰能夠結束管弦樂隊的惡劣表演。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 야크샤 전대가 가장 앞장서 연합 전대를 이끌겠습니다!","JPN":"私たちヤクシャー戦隊が先陣を切り、連合戦隊を導いてみせます！","ENG":"We, the Yaksha Division, will take the lead of the coalition divisions!","TWN":"我們夜叉戰隊將在最前方帶領聯合戰隊！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"말도 안 돼!","JPN":"あり得ないわ！","ENG":"This cannot be!","TWN":"不可能！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국 녀석들이 어떻게 가변 심도에 있는 이곳을……!!","JPN":"どうして管理局のやつらが、可変深度にあるこの場所を突き止めた……！？","ENG":"How did the Administration manage to enter the variable depths...?!","TWN":"管理局那些傢伙，是怎麼來到可變深度的……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"설마, 벌써 이곳에 다다를 수 있는 기술력을 손에 넣은 건가?","JPN":"まさか、もうここに辿り着ける技術力を手に入れたっていうの？","ENG":"Have they... already obtained the technology to reach this place?","TWN":"難道，他們已經掌握了可以達到這裡的技術了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"……셰나.","JPN":"……シェナ。","ENG":"...Shena.","TWN":"……世娜。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L42_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"관리국 녀석들이 코 앞까지 들이닥쳤어. 피해야 해.","JPN":"管理局のやつらが目の前まで来てる。早く退かないと。","ENG":"The Administration has reached our doorstep. We must retreat.","TWN":"管理局的人就快過來了。我們必須避開他們。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"오보에도, 하프도, 비올라도…… 벌써 최고 단원 여럿이 당했어.","JPN":"オーボエも、ハープも、ヴィオラも……首席奏者の多くがやられたわ。","ENG":"Oboe, Harp, and even Viloa... We have already lost many of the Elite Members.","TWN":"雙簧管、豎琴、中提琴……幾名樂手已經被殺。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"피한다고? 웃기지 마.","JPN":"退く？　ふざけないで。","ENG":"Retreat? Don’t make me laugh.","TWN":"避開？你在開什麼玩笑？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그림자 주제에 우리의 본분을 잊은 거야?","JPN":"シャドウのくせに、私たちの本分を忘れたのかしら？","ENG":"Have you forgotten our duty, Shadow?","TWN":"成了暗影，你就忘了我們的本分了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이 세계에 엘리시온의 연구 설비를 구현하느라 얼마나 고생을 했는데!","JPN":"この世界にエリシオンの研究設備を具現するために、どれだけ苦労したかを！","ENG":"Do you know how much effort we put into materializing Elysion's research facilities here?!","TWN":"你知道我們為了把艾利森的研究設施複製到這個世界上，費了多大的功夫嗎！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"실험체들도, 그동안의 연구 성과도 다 여기 남아있다고!","JPN":"実験体も、今までの研究成果もぜんぶここにあるのよ！","ENG":"The test subjects and even all our research results are here!","TWN":"迄今為止的實驗體和所有研究成果都保留在這裡！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그보다 카르멘은? 지휘자님이랑 같이 현실로 부상했잖아!","JPN":"それよりカルメンは？　指揮者様と一緒に現実に浮上しているんでしょう？","ENG":"And where's Carmen? She went with the Chief Conductor to the Normalside!","TWN":"卡門呢？她不是和指揮家一起躍出現世了嗎！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"글쎄? 그쪽도 나름대로 사정이 있는 거 아닐까?","JPN":"さあ、そっちにも事情があるんじゃない？","ENG":"Perhaps something is going on over there as well?","TWN":"這個……？她那邊可能遇上了什麼狀況？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"쳇, 완전히 양동 작전에 걸려들었잖아?","JPN":"ちっ、陽動作戦にみごとはめられたってことね。","ENG":"Tch! Did we completely fall for their feint operation?","TWN":"嘖，這下我們完全陷入被動了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"녀석들에게 가변 심도에 돌입할 기술이 존재할 줄이야!","JPN":"奴らに可変深度まで突入できる技術力があったとは……！","ENG":"Who would've thought that they would possess the technology to enter the variable depths!","TWN":"沒想到他們會有使用可變深度的技術！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어쩔 수 없네, 플라가.","JPN":"仕方ないわ、プラーガ。","ENG":"We have no choice, Plaga.","TWN":"沒辦法了，芙蕾佳。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"넌 단원들의 악기를 최대한 회수하고 현실로 부상해서 지휘자님께 이 사실을 알려.","JPN":"あなたは団員たちの楽器をできるだけ回収して現実に浮上しなさい。そして指揮者様に現状をお伝えして。","ENG":"You go gather as many instruments as you can and head to the Normalside to report what happened to the Chief Conductor.","TWN":"你必須盡可能取回成員的樂器，躍出到現世中，並報告給指揮家。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"단원인 우리는 그림자의 핵이 파괴돼도, 악기만 온전하면 존재의 연속성을 유지할 수 있어.","JPN":"団員の私たちはシャドウの核を破壊されても、楽器さえ無事なら存在の連続性を保つことができるわ。","ENG":"We can still maintain the continuity of our existence, even with our Shadow cores destroyed, as long as the instruments remain intact.","TWN":"作為樂團成員，即使暗影核心被摧毀，只要樂器完好無損，我們就可以維持存在的連續性。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님이 어떻게든 해주실 거야.","JPN":"指揮者様がなんとかしてくださるはずよ。","ENG":"Chief Conductor will resolve all this.","TWN":"指揮家知道該怎麼做的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"그럼, 너는 어떻게 하려고?","JPN":"それで、あなたはどうするつもり？","ENG":"Then what about you?","TWN":"那你接下來打算怎麼辦？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어떻게 하긴, 뭘 어떻게 해!?","JPN":"どうするもなにも！","ENG":"What about me?!","TWN":"我？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님이 돌아오셨을 때, 곁에 최고 단원이 하나도 남아있지 않으면, 어쩌려고.","JPN":"マエストロが戻られた時、首席奏者が一人も残ってないと困るでしょう？","ENG":"What if the Chief Conductor returns, but there are no more Elite Members?","TWN":"當指揮家回來時，身邊已經沒有一個樂手了，她會是什麼表情？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"제1 바이올린의 자리는 항상 지휘자님과 가장 가까운 곳이어야 해.","JPN":"第1バイオリンは、常に指揮者様から最も近い場所にいないといけないの。","ENG":"The concertmaster must always be right next to the Chief Conductor.","TWN":"首席小提琴手的位置必須一直是最靠近指揮家的地方。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇게 멍하니 있지 말고 서둘러!","JPN":"ぼうっとしていないで急ぎなさい！","ENG":"Then don’t just stand there and hurry!","TWN":"別發呆，快點！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국의 발목을 잡을 수단이라면 아직 남아 있어.","JPN":"管理局を足止めする手段なら、まだあるわ。","ENG":"I still have a means to keep the Administration here.","TWN":"還是有方法可以阻止管理局的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASSOON_HARMONY_NULL_NULL","text":{"KOREA":"……설마, 그 <color=#ffd34c>A타입</color>을 쓰려는 거야?","JPN":"……まさか、あの<color=#ffd34c>Aタイプ</color>を使うつもり？","ENG":"...You're not going to use the <color=#ffd34c>Type As</color>, are you?","TWN":"……難道，你想用那些<color=#ffd34c>A類</color>？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래, 혹시 몰라 폐기하지 않고 가사 상태로 보관해 둔 <color=#ffd34c>실패작</color>들.","JPN":"ええ、念のために破棄せずに仮死状態のまま保管しておいた<color=#ffd34c>失敗作</color>たち。","ENG":"I am. The <color=#ffd34c>failed products</color> that I kept in an idle state instead of discarding them, just in case.","TWN":"為了以防萬一，我沒有真的處理掉那些<color=#ffd34c>失敗品</color>。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예하의 성흔도 이어받지 못한 쓰레기들이지만, 적어도 관리국 녀석들의 발목은 잡아주겠지.","JPN":"猊下の聖痕すら受け継いでないゴミだらけだけど、管理局の奴らを引き留めるには十分でしょう。","ENG":"Although they are trash that couldn't inherit Her Eminence's Stigmata, they'll still be enough to slow down the Administration's advance.","TWN":"雖然他們廢得連主教的聖痕都繼承不了，但至少能擋住管理局的傢伙們。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어차피 오래 살지도 못하고 죽어버릴 거, 이렇게도 쓰는 편이 낫지 않겠어?","JPN":"長生きもできずにすぐ死んでしまう奴らよ。こんなことにでも使わせてもらったほうがいいじゃない？","ENG":"Plus, they won't even be able to live long anyway, so why not use them?","TWN":"反正他們也活不了多久了，廢物利用不是很好嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_LOGIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BASSOON_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"악기를 든 그림자! 저기 최고 단원이다!","JPN":"楽器を持つシャドウがいるぞ！　首席奏者だ！","ENG":"A Shadow with an instrument! There's an Elite Member over there!","TWN":"拿著樂器的暗影！那是樂手！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER_HARMONY_NPC_HORN","text":{"KOREA":"자, 잠깐……!!","JPN":"ま、待って……！！","ENG":"W-wait...!!","TWN":"等、等等……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전 대원, 일제 사격 개시!","JPN":"全隊員、一斉射撃！！","ENG":"All units, volley fire!","TWN":"全體隊員，準備發射！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MEMBER_HARMONY_NPC_HORN","text":{"KOREA":"으, 으아아아아아아……!","JPN":"う、うわわあああ……！","ENG":"A-aaaargh...!","TWN":"呃啊啊啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEMBER_HARMONY_NPC_HORN","text":{"KOREA":"사, 살려주세요! 최, 최고 지휘자님……!!","JPN":"た、助けてください！　首席指揮者様……！！","ENG":"S-save us! C-Chief Conductor...!","TWN":"救、救救我！首席指揮家……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"모두 그림자의 악기까지 철저히 파괴하도록 해.","JPN":"皆、シャドウが持っている楽器も確実に破壊するように。","ENG":"Make sure to completely destroy all Shadow instruments.","TWN":"要確保徹底破壞掉所有暗影的樂器。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 녀석들은 그림자 중에서도 제법 끈질긴 축에 속하니까 말이야.","JPN":"やつらはシャドウの中でもしぶとい方だからね。","ENG":"They tend to be particularly persistent, even among Shadows.","TWN":"這些傢伙算是暗影之中比較難纏的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음……?","JPN":"ん……？","ENG":"Hmm…?","TWN":"呃嗯……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"의외로 연주에 의존하지 않는구나?","JPN":"思ったほど演奏に集中してはいないのね。","ENG":"Guess this one doesn't really rely on performance. That's surprising.","TWN":"你不進行演奏嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"같은 엘리시움의 그림자라고 해도 다 성격이 제각각이네.","JPN":"同じエリシウムのシャドウでも、性格はばらばらなのね。","ENG":"I didn't realize that Elysium Shadows had different personalities.","TWN":"雖然都是樂團的暗影，但特性卻各有不同。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"오랜만이야, 바이올린이 셰나라고 했던가?","JPN":"久しぶり。バイオリンのシェナって言ったっけ？","ENG":"Long time no see. The violinist is Shena, right?","TWN":"好久不見了，小提琴手世娜？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"관리국이 키우는 가축들이 냄새를 맡고 여기까지 기어들어 왔네?","JPN":"管理局の家畜どもがここの匂いを嗅ぎつけて入り込んできたのね。","ENG":"Guess the Administration's livestock caught the scent of this place and crawled all the way here.","TWN":"管理局養的走狗聞著味道就爬到這裡來了？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"근데 미안해서 어쩌지? 멍청한 토끼한테 들려줄 만큼 내 연주는 싸구려가 아니거든.","JPN":"悪いけど。愚かなウサギに聞かせられるほど、私の演奏は安くないのよ。","ENG":"But unfortunately for you, my performance isn't cheap enough for me to play for a stupid bunny like you.","TWN":"但是很抱歉，一隻愚蠢的兔子還不值得我演奏。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"여기까지 온 건 칭찬해 줄게, 설마 그 가변 심도의 영역을…….","JPN":"ここまで来れたことは褒めてあげるわ。まさかあの可変深度の領域を……","ENG":"I commend you for coming this far. Who knew you'd make it to the variable depths–","TWN":"你能來到這裡值得讓我稱讚，畢竟我們從未想過可變深度……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……매너가 영 꽝이네. 짐승들이라 예의를 모르는 걸까?","JPN":"……マナーがなってないわね。やぱり獣だからかな？","ENG":"...Rude! But then again, animals don't have any manners.","TWN":"……舉止真粗魯。動物都是不懂禮貌的嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"글쎄? 우리가 서로 예의나 지킬 정도로 친한 사이는 아니었던 것 같은데?","JPN":"さあ？　私たちって、礼儀を守るほど近しい仲だった？","ENG":"Well, I don't think we're close enough to be polite to each other, no?","TWN":"這個嘛？我認為我們的關係，也沒有好到需要以禮相待吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리가 좀 바빠서.","JPN":"こっちはちょっと忙しいの。","ENG":"We're kinda busy right now.","TWN":"我們很忙的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"잘난 지휘자가 무대에 도착하기 전에 너희 악기들을 전부 박살 낼 예정이거든.","JPN":"偉い指揮者さんが舞台に着く前に、あなたたちの楽器を全部ぶっ壊さないといけないんだよね。","ENG":"You see, we're going to destroy all your instruments before your conductor steps onto the stage.","TWN":"我們會趕在你們偉大的指揮家上台之前毀掉所有的樂器。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러니 너희들이 남길 수 있는 말은 작별 인사뿐이야.","JPN":"だから、最後の挨拶ぐらいなら聞いてあげる。","ENG":"So, the only thing you can do is to say goodbye.","TWN":"所以，你們能說的就只剩下告別了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"얌전히 죽어주지 않을래? 셰나?","JPN":"大人しく死んでくれない？　シェナ。","ENG":"Just accept your death, Shena.","TWN":"不如就乖乖地受死吧？世娜？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후후, 글쎄? 그리 쉽지는 않을 걸?","JPN":"ふふ、そう簡単にいくかしら？","ENG":"Fuu fuu, is that so? But it won't be that easy.","TWN":"呵呵，是嗎？這可沒那麼容易喔？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우리에게도 아직 남겨둔 패가 있거든.","JPN":"こっちにもまだ手札は残っているのよ。","ENG":"We also have a surprise for you.","TWN":"我們還有最後一張底牌呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, 너희 차례야, A타입……!!","JPN":"さあ、行きなさい。Aタイプ……！！","ENG":"Go, Type As...!","TWN":"好了，現在輪到你們了，A類……！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐음…… 악질이네…….","JPN":"ふうん……悪趣味ね……","ENG":"Hmm... You are really horrible.","TWN":"唔……真是惡劣……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"멘탈프린팅의 실험체를 위해 인간을 납치한다는 이야기를 들었는데.","JPN":"人間をさらってメンタル・プリンティングの実験台にしているって話は聞いたけど。","ENG":"I heard of humans being kidnapped as test subjects for Mental Printing.","TWN":"我聽說你們擄走人類進行智力複印實驗……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아예 작정하고 복제 인간을 실험체로 쓰고 있었을 줄은 몰랐어.","JPN":"複製人間まで使っていたとは。","ENG":"But I had no idea you were using clones as test subjects.","TWN":"但沒想到還有複製人實驗體。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이 녀석들은 카운터도 뭣도 아닌, 그냥 말 잘 듣는 실패작일 뿐이야.","JPN":"こいつらはカウンターでもなんでもない、従順な失敗作にすぎないわ。","ENG":"They aren't Counters, but merely submissive failed products.","TWN":"這些東西連制裁者都不是，只不過是聽話的失敗品而已。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 그런 실패작이라고 해도 이 정도의 숫자라면 어느 정도는 시간을 벌어주겠지.","JPN":"そんな失敗作でもこれだけの数があれば時間稼ぎには役立つでしょう。","ENG":"But even if they are failed products, the sheer number of them will be enough to buy me some time.","TWN":"但即使如此，能為我們贏得一些時間就夠了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전 대원, 교전 준비!","JPN":"全隊員、交戦準備を！","ENG":"Everyone, prepare for battle!","TWN":"全體隊員，準備交戰！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"엘리시움의 그림자는 내가 처리할게. 다른 복제 인간의 상대를 부탁해.","JPN":"エリシウムのシャドウは私が始末する。皆は複製人間の相手を頼むよ。","ENG":"I'll take care of the Elysium Shadow. The rest of you focus on the clones.","TWN":"我來處理樂團的暗影。剩下的複製人就交給你們對付了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, A타입……!","JPN":"さあ、Aタイプ……！","ENG":"Now, Type As...!","TWN":"上吧，A類……！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너희들의 목숨을 전부 소모해서라도, 관리국 녀석들을 막아!!","JPN":"命尽きるまで、管理局の奴らを引き留めなさい！","ENG":"Stop the Administration dogs with all your life!","TWN":"就算付出你們的性命，也要阻止管理局的人！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};